from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English paragraph. Handles mission/crewMembers aggregation to
    produce compact sentences.
    """
    if not triples:
        return ""

    # ---------- Helper utilities ----------
    def fmt_date(d: str) -> str:
        try:
            from datetime import datetime
            dt = datetime.strptime(d, "%Y-%m-%d")
            # Use platform‑independent day format
            return dt.strftime("%B %-d, %Y") if hasattr(dt, "strftime") else dt.strftime("%B %d, %Y")
        except Exception:
            return d

    def join_names(names: list[str]) -> str:
        """Join a list of names with commas and 'and'."""
        if not names:
            return ""
        if len(names) == 1:
            return names[0]
        if len(names) == 2:
            return f"{names[0]} and {names[1]}"
        return f"{', '.join(names[:-1])}, and {names[-1]}"

    # ---------- Phrase builder ----------
    def phrase(subj: str, pred: str, obj: str) -> str:
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            low = obj.lower()
            if low in ("united states", "usa", "united states of america"):
                return "American"
            # Preserve original capitalization for other nationalities
            return obj
        if p == "leader":
            return f"{obj} is the {subj} leader"
        if p == "occupation":
            return f"served as a {obj.lower()}"
        if p == "dateofretirement":
            # Handles retirement dates like "June 1981" or ISO dates
            return f"retired in {obj}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is now retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                parts = []
                if hrs:
                    parts.append(f"{hrs} hour{'s' if hrs != 1 else ''}")
                if rem:
                    parts.append(f"{rem} minute{'s' if rem != 1 else ''}")
                return "spent " + " and ".join(parts) + " in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"{obj} operated {subj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        if p == "partstype":
            # Expected format: "List of <plural> in <Place>"
            # Produce "<subject> is a <singular> in <Place>"
            parts = obj.split()
            # Find the word after "of" (usually plural noun) and the word after "in" (location)
            try:
                of_index = parts.index("of")
                noun_plural = parts[of_index + 1]
            except ValueError:
                noun_plural = parts[-1]
            try:
                in_index = parts.index("in")
                location = " ".join(parts[in_index + 1 :])
            except ValueError:
                location = ""
            # improved singularization
            if noun_plural.endswith("ies"):
                noun = noun_plural[:-3] + "y"
            elif noun_plural.endswith("s"):
                noun = noun_plural[:-1]
            else:
                noun = noun_plural
            if location:
                return f"is a {noun} in {location}"
            else:
                return f"is a {noun}"
        # generic fallback
        return f"is {obj}"

    # ---------- Aggregate mission/crew data ----------
    from collections import defaultdict

    # Store role information per mission
    mission_info: dict[str, dict[str, list[str]]] = defaultdict(
        lambda: {"commander": [], "backupPilot": [], "crew": [], "operator": None}
    )
    other_triples: list[Triple] = []

    for t in triples:
        p = t.predicate.lower().replace(" ", "")
        if p == "mission":
            # subject is astronaut, object is mission
            mission_info[t.object]["crew"].append(t.subject)
        elif p == "crewmembers":
            mission_info[t.subject]["crew"].append(t.object)
        elif p == "commander":
            # subject is mission, object is person
            mission_info[t.subject]["commander"].append(t.object)
        elif p == "backuppilot":
            mission_info[t.subject]["backupPilot"].append(t.object)
        elif p == "operator":
            # Capture operator for the mission to use in sentence construction
            mission_info[t.subject]["operator"] = t.object
        else:
            other_triples.append(t)

    sentences: list[str] = []

    # Build sentences per mission, preferring a compact natural‑language formulation
    for mission, roles in mission_info.items():
        cmd_list = roles["commander"]
        bp_list = roles["backupPilot"]
        crew_list = roles["crew"]
        op = roles.get("operator")

        mission_sentences: list[str] = []

        # Operator clause (stand‑alone)
        if op:
            mission_sentences.append(f"{mission} was operated by {op}")

        # Main crew clause
        if cmd_list:
            cmd = join_names(cmd_list)
            # If we have other participants, describe their relation to the commander
            if crew_list or bp_list:
                parts = []
                if crew_list:
                    crew_names = join_names(crew_list)
                    parts.append(f"crew member {crew_names}")
                if bp_list:
                    bp_names = join_names(bp_list)
                    parts.append(f"backup pilot {bp_names}")
                # Join crew/backup parts with 'and'
                crew_part = " and ".join(parts)
                mission_sentences.append(
                    f"{crew_part} served under commander {cmd} on {mission}"
                )
            else:
                # Commander only
                mission_sentences.append(f"{cmd} was the commander of {mission}")
        else:
            # No commander – just list available roles
            if crew_list:
                crew_names = join_names(crew_list)
                mission_sentences.append(f"{crew_names} was a crew member of {mission}")
            if bp_list:
                bp_names = join_names(bp_list)
                mission_sentences.append(f"{bp_names} was the backup pilot of {mission}")

        # Combine the parts for this mission into a single sentence (or two if operator present)
        if mission_sentences:
            if len(mission_sentences) == 1:
                sentences.append(mission_sentences[0] + ".")
            else:
                # Join with a period and a space for readability
                sentences.append(". ".join(mission_sentences) + ".")

    # Process remaining triples (those not mission/crewMembers)
    # Group by subject, handling nationality specially to prepend as adjective
    groups = defaultdict(list)
    for t in other_triples:
        groups[t.subject].append(t)

    def _article(word: str) -> str:
        """Return appropriate indefinite article for a word ('a' or 'an')."""
        return "an" if word[0].lower() in "aeiou" else "a"

    for subj, items in groups.items():
        # Separate nationality descriptor and keep original object
        nat_adj = None
        nat_obj = None
        other_desc = []
        for t in items:
            pred_key = t.predicate.lower().replace(" ", "")
            if pred_key == "nationality":
                nat_adj = phrase(subj, t.predicate, t.object).strip()
                nat_obj = t.object.strip().strip('"')
            else:
                other_desc.append(phrase(subj, t.predicate, t.object))
        # Build subject string with optional nationality adjective
        if nat_adj and not other_desc:
            # Only nationality information – produce a clearer sentence
            # Use the original object to avoid loss of specificity
            # Prefer article form for common nationalities
            low = nat_obj.lower()
            if low in ("united states", "usa", "united states of america"):
                sentences.append(f"{subj} is an American.")
            else:
                # Use 'a' or 'an' appropriately
                article = "an" if nat_obj[0].lower() in "aeiou" else "a"
                sentences.append(f"{subj} is {article} {nat_obj}.")
            continue

        subject_str = f"{nat_adj} {subj}" if nat_adj else subj

        if not other_desc:
            sentences.append(f"{subject_str}.")
        elif len(other_desc) == 1:
            sentences.append(f"{subject_str} {other_desc[0]}.")
        else:
            body = ", ".join(other_desc[:-1])
            sentences.append(f"{subject_str} {body}, and {other_desc[-1]}.")
    return " ".join(sentences)

# EVOLVE-BLOCK-END

